package com.pinova.api.controller;import com.pinova.api.request.*;import com.pinova.api.response.*;import com.pinova.api.web.CurrentAdminResolver;import com.pinova.common.api.ApiResponse;import com.pinova.service.AdminInventoryService;import com.pinova.service.command.*;import com.pinova.service.model.*;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/admin/inventory") public class AdminInventoryController{private final AdminInventoryService service;private final CurrentAdminResolver resolver;public AdminInventoryController(AdminInventoryService s,CurrentAdminResolver r){service=s;resolver=r;}
 @GetMapping("/warehouses") public ApiResponse<List<AdminWarehouseResponse>> warehouses(HttpServletRequest r){return ApiResponse.success(service.listWarehouses(resolver.requireCurrentAdmin(r)).stream().map(AdminInventoryController::warehouse).toList());}
 @PostMapping("/warehouses") public ApiResponse<AdminWarehouseResponse> create(@Valid @RequestBody SaveWarehouseRequest b,HttpServletRequest r){return ApiResponse.success(warehouse(service.saveWarehouse(command(resolver.requireCurrentAdmin(r),null,b))));}
 @PutMapping("/warehouses/{id}") public ApiResponse<AdminWarehouseResponse> update(@PathVariable Long id,@Valid @RequestBody SaveWarehouseRequest b,HttpServletRequest r){return ApiResponse.success(warehouse(service.saveWarehouse(command(resolver.requireCurrentAdmin(r),id,b))));}
 @GetMapping("/stocks") public ApiResponse<List<AdminStockResponse>> stocks(@RequestParam(required=false)Long warehouseId,@RequestParam(required=false)Long skuId,HttpServletRequest r){return ApiResponse.success(service.listStocks(resolver.requireCurrentAdmin(r),warehouseId,skuId).stream().map(AdminInventoryController::stock).toList());}
 @PostMapping("/stocks/{id}/adjustments") public ApiResponse<AdminStockResponse> adjust(@PathVariable Long id,@Valid @RequestBody AdjustInventoryRequest b,HttpServletRequest r){return ApiResponse.success(stock(service.adjust(new AdjustInventoryCommand(resolver.requireCurrentAdmin(r),id,b.transactionNo(),b.mode(),b.quantity(),b.version(),b.reason()))));}
 private static SaveWarehouseCommand command(AuthenticatedAdminResult a,Long id,SaveWarehouseRequest b){return new SaveWarehouseCommand(a,id,b.shopId(),b.warehouseCode(),b.name(),b.warehouseType(),b.status(),b.version());}private static AdminWarehouseResponse warehouse(AdminWarehouseResult w){return new AdminWarehouseResponse(String.valueOf(w.id()),String.valueOf(w.shopId()),w.warehouseCode(),w.name(),w.warehouseType(),w.status(),w.version());}private static AdminStockResponse stock(AdminStockResult s){return new AdminStockResponse(String.valueOf(s.id()),String.valueOf(s.warehouseId()),String.valueOf(s.skuId()),s.onHandQuantity(),s.reservedQuantity(),s.availableQuantity(),s.version());}}
